class Solution:
    def maximumEvenSplit(self, finalSum: int) -> List[int]:
        if finalSum % 2 != 0:
            return []
        result = []
        current = 2
        while finalSum > 0:
            if finalSum - current >= 0 and (not result or current not in result):
                result.append(current)
                finalSum -= current
                current += 2
            else:
                break
        if finalSum == 0:
            return result
        else:
            return []
